--
-- AgroLink Platform — sandbox TEST data (local development only).
--
-- WARNING: This file contains fake farmers, organizations, contracts,
-- loans, orders, and other transactional rows generated while building
-- and testing this project in the sandbox. It is provided ONLY as a
-- convenience for populating a local development database with realistic
-- sample data so the UI has something to show.
--
-- DO NOT run this file against the Render (production/pilot) database.
-- The pilot must start empty of business data — see 04_reference_data.sql
-- for the reference/config rows the app actually needs in production.
--

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;

-- contract.contract / risk.credit_score / underwriting.loan_application
-- have FORCE ROW LEVEL SECURITY, which makes RLS apply even to the table
-- owner. If you're restoring this as a non-superuser role, temporarily
-- drop FORCE so the COPY below can insert rows; re-enabled at the bottom
-- of this file. (Harmless no-op if you're running as a superuser, which
-- already bypasses RLS regardless.)
ALTER TABLE contract.contract NO FORCE ROW LEVEL SECURITY;
ALTER TABLE risk.credit_score NO FORCE ROW LEVEL SECURITY;
ALTER TABLE underwriting.loan_application NO FORCE ROW LEVEL SECURITY;













































ALTER TABLE contract.contract FORCE ROW LEVEL SECURITY;
ALTER TABLE risk.credit_score FORCE ROW LEVEL SECURITY;
ALTER TABLE underwriting.loan_application FORCE ROW LEVEL SECURITY;
